// Docuseal envoie l'evenement form.completed apres signature.
// Les metadonnees du rendez-vous sont dans data.metadata (posees a la creation).
const body = $json.body || $json;
const data = body.data || {};
const meta = data.metadata || {};

// Si l'evenement ne provient pas de notre flux (pas de date), on ignore.
if (!meta.date || !meta.heure) {
  return [];
}

// Dates de debut/fin au format Zoho Calendar (gere automatiquement
// l'heure d'ete / hiver via le fuseau Europe/Paris).
const start = DateTime.fromISO(`${meta.date}T${meta.heure}`, { zone: 'Europe/Paris' });
const end = start.plus({ hours: 1 });
const zohoFmt = "yyyyLLdd'T'HHmmssZZZ";

const eventdata = JSON.stringify({
  dateandtime: {
    timezone: 'Europe/Paris',
    start: start.toFormat(zohoFmt),
    end: end.toFormat(zohoFmt),
  },
  title: `Devis - ${meta.devis_numero || ''}-${meta.prenom || ''} ${meta.nom || ''}`.trim(),
  location: meta.adresse || '',
  description: `Client: ${meta.prenom || ''} ${meta.nom || ''}\nTel: ${meta.telephone || ''}\nEmail: ${meta.email || ''}\nSurface: ${meta.surface_m2 || ''} m2\nType: ${meta.type_toiture || ''}\nDevis: ${meta.devis_total_ttc || ''} EUR`,
  isallday: false,
});

return [{ json: { eventdata } }];
